function user_profile_uploads_enqueue_scripts() {
    wp_enqueue_script( 'user-profile-uploads', plugins_url( 'js/user-profile-uploads.js', __FILE__ ), array( 'jquery' ), '1.0', true );
}
add_action( 'admin_enqueue_scripts', 'user_profile_uploads_enqueue_scripts' );

function user_profile_uploads_add_meta_box() {
    add_meta_box( 'user-profile-uploads', 'Profile Uploads', 'user_profile_uploads_meta_box', 'user', 'normal', 'high' );
}
add_action( 'add_user_meta_boxes', 'user_profile_uploads_add_meta_box' );

function user_profile_uploads_meta_box( $user ) {
    ?>
    <label for="profile_picture">Profile Picture:</label>
    <input type="file" name="profile_picture" id="profile_picture" accept="image/*" />

    <label for="documents">Documents:</label>
    <input type="file" name="documents[]" id="documents" accept=".pdf, .doc, .docx" multiple />
    <?php
}

function user_profile_uploads_save_user_meta( $user_id ) {
    if ( ! isset( $_FILES['profile_picture'] ) || ! isset( $_FILES['documents'] ) ) {
        return;
    }

    // Profile picture upload
    $profile_picture = $_FILES['profile_picture'];
    $profile_picture_upload = wp_upload_bits( $profile_picture['name'], null, file_get_contents( $profile_picture['tmp_name'] ) );
    update_user_meta( $user_id, 'profile_picture', $profile_picture_upload['url'] );

    // Documents upload
    $documents = $_FILES['documents'];
    foreach ( $documents['name'] as $key => $document_name ) {
        $document_upload = wp_upload_bits( $document_name, null, file_get_contents( $documents['tmp_name'][$key] ) );
        update_user_meta( $user_id, 'document_' . $key, $document_upload['url'] );
    }
}
add_action( 'personal_options_update', 'user_profile_uploads_save_user_meta' );